import{P as o,T as i}from"./chunks/TrustPilotReviewCollector.cvDT7dNC.js";import{o as s,c as r,ae as t,E as e}from"./chunks/framework.DshwfISk.js";import"./chunks/site-runtime.BQe22JlB.js";const m=JSON.parse('{"title":"Politica de privacidade","description":"","frontmatter":{},"headers":[],"relativePath":"privacypolicy.md","filePath":"privacypolicy.md","lastUpdated":1774899612000}'),d={name:"privacypolicy.md"},h=Object.assign(d,{setup(c){return(l,a)=>(s(),r("div",null,[a[0]||(a[0]=t('<h1 id="politica-de-privacidade" tabindex="-1">Politica de privacidade <a class="header-anchor" href="#politica-de-privacidade" aria-label="Permalink to &quot;Politica de privacidade&quot;">​</a></h1><h2 id="escopo" tabindex="-1">Escopo <a class="header-anchor" href="#escopo" aria-label="Permalink to &quot;Escopo&quot;">​</a></h2><p>Esta pagina descreve como <code>mozg.com.br</code>, seus exports publicos, formularios de contato e apps derivados tratam dados pessoais, analytics e artefatos tecnicos.</p><h2 id="dados-que-podem-ser-tratados" tabindex="-1">Dados que podem ser tratados <a class="header-anchor" href="#dados-que-podem-ser-tratados" aria-label="Permalink to &quot;Dados que podem ser tratados&quot;">​</a></h2><ul><li>dados de navegacao e request metadata minimos para a operacao publica, como <code>request_id</code>, <code>timestamp</code>, <code>path</code>, <code>method</code> e sinais equivalentes;</li><li>dados enviados voluntariamente em contato direto, formularios, email ou plataformas externas;</li><li>sinais anonimizados ou agregados vindos de analytics, ads e widgets publicos quando habilitados no ambiente de publicacao.</li></ul><h2 id="finalidades" tabindex="-1">Finalidades <a class="header-anchor" href="#finalidades" aria-label="Permalink to &quot;Finalidades&quot;">​</a></h2><ul><li>responder contato profissional e contextualizar oportunidades;</li><li>medir disponibilidade, desempenho, descoberta de conteudo e interesse em superficies publicas;</li><li>manter portfolio, Storybook, apps Android e artefatos tecnicos auditaveis;</li><li>reforcar prova social publica por meio de superficies como Trustpilot e perfis tecnicos complementares.</li></ul><h2 id="servicos-e-integracoes-publicas" tabindex="-1">Servicos e integracoes publicas <a class="header-anchor" href="#servicos-e-integracoes-publicas" aria-label="Permalink to &quot;Servicos e integracoes publicas&quot;">​</a></h2><p>O site pode carregar, conforme configuracao do ambiente, integracoes como Cloudflare Web Analytics, Google Analytics, Google Tag Manager, Google Ads, LinkedIn Insight Tag, Meta Pixel, Zoho SalesIQ, Google Custom Search e Trustpilot.</p><p>Cada integracao segue a propria politica e opera como superficie externa. Quando possivel, a configuracao privilegia metadados explicitos, carga assincroma e URLs publicas verificaveis.</p><h2 id="apps-e-superficies-derivadas" tabindex="-1">Apps e superficies derivadas <a class="header-anchor" href="#apps-e-superficies-derivadas" aria-label="Permalink to &quot;Apps e superficies derivadas&quot;">​</a></h2><ul><li><code>Mozg TWA</code>: distribuido no Google Play em <code>br.com.mozg.twa</code>.</li><li><code>Mozg Hibrido</code>: distribuido no Google Play em <code>com.mozg.android.fizzy</code>.</li><li><code>@mozgbrasil/node-web-components</code>: pacote npm publico com Storybook publicado e exemplos auditaveis.</li></ul><h2 id="direitos-e-contato" tabindex="-1">Direitos e contato <a class="header-anchor" href="#direitos-e-contato" aria-label="Permalink to &quot;Direitos e contato&quot;">​</a></h2><p>Para solicitar esclarecimentos, atualizacao ou remocao de dados enviados voluntariamente, use:</p><ul><li><a href="mailto:mozgbrasil@gmail.com" target="_blank" rel="noreferrer">Email</a></li><li><a href="https://www.linkedin.com/in/mozgbrasil/" target="_blank" rel="noreferrer">LinkedIn</a></li><li><a href="https://mozg.com.br/contato" target="_blank" rel="noreferrer">Pagina de contato</a></li></ul><h2 id="atualizacoes" tabindex="-1">Atualizacoes <a class="header-anchor" href="#atualizacoes" aria-label="Permalink to &quot;Atualizacoes&quot;">​</a></h2><p>Esta politica pode evoluir quando novas superficies publicas, apps, componentes ou integracoes forem adicionados ao ecossistema MOZG.</p>',17)),e(o),e(i)]))}});export{m as __pageData,h as default};
